const trigger = String($('Preferir Mensagem Tool').first()?.json?.mensagem || '');
const isAll = /CATALOGO_CARDS\[all\]/i.test(trigger);
const all = $input.all();
if (!all || all.length === 0) return [];
if (isAll) return all;
return [all[0]];

function toBRL(v){if(v==null||v==='')return'';const n=Number(v);if(!Number.isFinite(n))return'';try{return n.toLocaleString('pt-BR',{style:'currency',currency:'BRL'});}catch(e){return'R$ '+n.toFixed(2).replace('.',',');}}
function caption(it){const emoji = it.tipo === 'Serviço' ? '🛠️' : '🛒';const titulo = `${emoji} ${String(it.nome||'').trim()}`.trim();const resumo = String(it.descricao||'').trim();const preco = toBRL(it.valor);const linhas = [];if(titulo) linhas.push(titulo);if(resumo){linhas.push('');linhas.push(resumo);}if(preco){linhas.push('');linhas.push(`💰 ${preco}`);}return linhas.join('\n').trim();}
function safe(v){return v==null?'':String(v);}

// Acesso ultra-seguro aos dados para evitar Unknown Error
const conn = $('Obter conexão e empresa1').first()?.json || {};
const dados = $('Dados').first()?.json || {};

const apiUrl=safe(conn.api_url).replace(/\/+$/,'');
const instance=safe(conn.nome_api||conn.instance);
const apikey=safe(conn.apikey||conn.globalkey||conn.apiKey||'');

const empresa_id=safe(conn.empresa_id||conn.empresa||dados.empresa_id||dados.empresa||'');
const remoteJid=safe(dados.TelefoneRaw||dados.Telefone||'');
const number=remoteJid.replace(/\D/g,'');

const input=$input.all().map(i=>i.json).filter(Boolean);
const items=input.map((it)=>({
  json:{
    ...it,
    apiUrl,
    instance,
    apikey,
    empresa_id,
    remoteJid,
    number,
    caption: caption(it),
    imageUrl: safe(it.image_url||it.imagem_url||it.foto_url||it.image_Url||''),
    fileName: (safe(it.nome||'produto').slice(0,32).replace(/[^\w\s.-]/g,'').trim()||'produto') + '.jpg'
  }
}));
return items;

const list = (items || []).map(i => i.json).filter(Boolean);
if (list.length === 0) return [];
list.sort((a, b) => {
  const at = Date.parse(String(a.updated_at || a.created_at || '')) || 0;
  const bt = Date.parse(String(b.updated_at || b.created_at || '')) || 0;
  return bt - at;
});
return [{ json: list[0] }];

