function pickMensagem(j) {
  const direct = typeof j?.mensagem === 'string' ? j.mensagem.trim() : '';
  if (direct) return direct;

  if (typeof j?.output === 'string') {
    const s = j.output.trim();
    if (s) return s;
  }

  const nested = typeof j?.output?.mensagem === 'string' ? j.output.mensagem.trim() : '';
  if (nested) return nested;

  const nested2 = typeof j?.output?.json?.mensagem === 'string' ? j.output.json.mensagem.trim() : '';
  if (nested2) return nested2;

  return '';
}

const withMsg = (items || [])
  .map((i) => {
    const msg = pickMensagem(i?.json);
    if (!msg) return i;
    return { ...i, json: { ...i.json, mensagem: msg } };
  })
  .filter((i) => Boolean(pickMensagem(i?.json)));

if (withMsg.length > 0) {
  return withMsg;
}

const patched = (items || []).map((i) => {
  const out = String(i?.json?.output ?? i?.json?.mensagem ?? '').trim();
  const lowered = out.toLowerCase();

  const hasToolBooleans = typeof i?.json?.agendamento_ok === 'boolean' || typeof i?.json?.cancel_ok === 'boolean';
  if (hasToolBooleans) return i;

  const looksLikeHallucinatedBooking =
    lowered.includes('já existe agendamento') ||
    lowered.includes('horário indisponível') ||
    lowered.includes('agendamento confirmado') ||
    lowered.includes('já está confirmado') ||
    lowered.includes('confirmado');

  const looksLikeTechExcuse =
    lowered.includes('dificuldade técnica') ||
    lowered.includes('probleminha técnico') ||
    lowered.includes('problema técnico');

  const looksLikeCatalogRequest =
    lowered.includes('catálogo') ||
    lowered.includes('catalogo') ||
    lowered.includes('produtos') ||
    lowered.includes('serviços');

  if (!out) return i;

  if (looksLikeCatalogRequest && !out.includes('CATALOGO_CARDS')) {
    return {
      ...i,
      json: {
        ...i.json,
        mensagem: 'CATALOGO_CARDS[all]',
      },
    };
  }

  const match = out.match(/CATALOGO_CARDS\[(.*?)\]/);
  if (match) {
    return {
      ...i,
      json: {
        ...i.json,
        mensagem: out,
        search_term: match[1] === 'all' ? '' : match[1]
      },
    };
  }

  if (looksLikeHallucinatedBooking || looksLikeTechExcuse) {
    return {
      ...i,
      json: {
        ...i.json,
        mensagem: 'Para eu agendar corretamente, me confirme o serviço e o dia/horário desejado (ex.: 30/03 às 10h).',
      },
    };
  }

  return i;
});

return patched;

const redis1 = JSON.parse($json.Redis1);
const redis2 = JSON.parse($json.Redis2);

const combinadoSemDuplicatas = Array.from(new Set([...redis1, ...redis2]));

const mensagem = combinadoSemDuplicatas.join(" ");

const dados = $('Dados').first().json;

return [{ 
  json: { 
    mensagem_completa: mensagem,
    telefone: dados.TelefoneRaw || dados.Telefone || dados.sender,
    nome: dados.NomeWpp,
    empresa_id: dados.empresa_id
  } 
}];

const raw = String($('Dados').first().json['message.content'] || '').trim();
const txt = raw.toLowerCase().replace(/\s+/g,' ').trim();
const current = String($json.mensagem || '').trim();

if (/CATALOGO_CARDS\[[^\]]+\]/i.test(current)) {
  return $input.all();
}

const greetings = /^(oi|ol[aá]|bom dia|boa tarde|boa noite|tudo bem|e ai|ei|opa|ok|obrigad[oa]|blz|beleza)(\W+)?$/i;
if (greetings.test(txt)) {
  return $input.all();
}

const kw = /(catalogo|catálogo|produto|produtos|servi[cç]o|servi[cç]os|pacote|pacotes|passeio|passeios|op[cç][aã]o|op[cç][oõ]es|pre[cç]o|precos|valor|valores|quanto\s+custa|data|datas|disponibilid|or[cç]amento|orcamento)/i;

const destinationOnly = txt.length > 0 && txt.length <= 25 && !/\d/.test(txt) && !kw.test(txt);
const catalogIntent = kw.test(txt) || destinationOnly;

if (!catalogIntent) {
  return $input.all();
}

let term = 'all';
if (destinationOnly) {
  term = raw;
} else {
  const m = raw.match(/para\s+([^\n,.!?]+)|de\s+([^\n,.!?]+)/i);
  const picked = (m ? (m[1] || m[2] || '') : '').trim();
  term = picked || 'all';
}

term = term.replace(/\/[a-z]{2,}$/i, '').replace(/\s+/g,' ').trim();
if (!term) term = 'all';

return $input.all().map(i => ({
  ...i,
  json: { ...i.json, mensagem: `CATALOGO_CARDS[${term}]` }
}));
